// 画面弹窗组件 - 用于加载指定的视图/画面，支持React代码渲染
interface ViewPanelProps {
    data: any
    onClose: () => void
    hidenCloseBtn?: boolean
    viewId?: string
    viewConfig?: any
    viewCode?: string
}

export const ViewPanel: React.FC<ViewPanelProps> = ({
    data,
    onClose,
    hidenCloseBtn = false,
    viewId,
    viewConfig,
    viewCode
}) => {
    const [error, setError] = React.useState<string | null>(null)
    const [ViewComponent, setViewComponent] = React.useState<React.ComponentType<any> | null>(null)

    React.useEffect(() => {
        // 如果提供了 viewCode，执行 React 代码来渲染画面
        if (viewCode) {
            try {
                let processedCode = viewCode

                // 检测是否包含 JSX 语法
                const hasJSX = /<[A-Za-z]/.test(viewCode)

                // 简单的 JSX 转译器 (支持嵌套)
                const transpileJSX = (code: string) => {
                    // 占位符映射
                    const placeholders: string[] = [];
                    const generatePlaceholder = (content: string) => {
                        placeholders.push(content);
                        return `%%JSX_PLACEHOLDER_${placeholders.length - 1}%%`;
                    };

                    // 1. 预处理：保护代码块中的字符串和表达式，防止解析干扰
                    // 暂时只做基础处理，假定用户代码格式相对规范

                    // 2. 从内向外替换成 React.createElement
                    // 循环查找不包含其他标签的"最内层"标签
                    let processed = code;
                    const tagRegex = /<([a-zA-Z][\w:-]*)([^>]*)>([^<]*)<\/\1>|<([a-zA-Z][\w:-]*)([^>]*)\/>/g;

                    let match;
                    let maxLoop = 1000; // 防止死循环

                    while ((match = tagRegex.exec(processed)) && maxLoop > 0) {
                        maxLoop--;
                        const fullMatch = match[0];
                        const isSelfClosing = !!match[4];
                        const tagName = isSelfClosing ? match[4] : match[1];
                        const attrs = isSelfClosing ? match[5] : match[2];
                        const childrenContent = isSelfClosing ? '' : match[3];

                        // 解析属性
                        const propsObjParts: string[] = [];
                        const attrRegex = /([\w:-]+)\s*=\s*(?:"([^"]*)"|'([^']*)'|\{([^}]+)\})/g;
                        let attrMatch;
                        while ((attrMatch = attrRegex.exec(attrs)) !== null) {
                            const [_, key, doubleQuoteVal, singleQuoteVal, exprVal] = attrMatch;
                            if (exprVal) {
                                propsObjParts.push(`${key}: ${exprVal}`);
                            } else {
                                const val = doubleQuoteVal !== undefined ? doubleQuoteVal : singleQuoteVal;
                                propsObjParts.push(`${key}: "${val}"`);
                            }
                        }
                        const propsObj = propsObjParts.length > 0 ? `{ ${propsObjParts.join(', ')} }` : 'null';

                        // 解析子元素
                        let childrenArgs = '';
                        if (childrenContent) {
                            // 分割文本和占位符/表达式
                            // 简单的处理：如果包含 placeholder，则按 placeholder 分割
                            // 否则视为文本或表达式

                            const parts: string[] = [];
                            let lastIndex = 0;
                            const childRegex = /(%%JSX_PLACEHOLDER_\d+%%)|(\{[^}]+\})/g;
                            let childMatch;

                            while ((childMatch = childRegex.exec(childrenContent)) !== null) {
                                // 添加前面的文本
                                if (childMatch.index > lastIndex) {
                                    const text = childrenContent.substring(lastIndex, childMatch.index);
                                    if (text.trim()) {
                                        const safeText = text.replace(/"/g, '\\"').replace(/\n/g, '\\n');
                                        parts.push(`"${safeText}"`);
                                    }
                                }

                                const part = childMatch[0];
                                if (part.startsWith('%%')) {
                                    // 还原占位符对应的代码
                                    const index = parseInt(part.match(/\d+/)![0]);
                                    parts.push(placeholders[index]);
                                } else {
                                    // 表达式 {xxx} -> xxx
                                    parts.push(part.slice(1, -1));
                                }

                                lastIndex = childMatch.index + part.length;
                            }

                            // 添加剩余文本
                            if (lastIndex < childrenContent.length) {
                                const text = childrenContent.substring(lastIndex);
                                if (text.trim()) {
                                    const safeText = text.replace(/"/g, '\\"').replace(/\n/g, '\\n');
                                    parts.push(`"${safeText}"`);
                                }
                            }

                            if (parts.length > 0) {
                                childrenArgs = ', ' + parts.join(', ');
                            }
                        }

                        const createElementCode = `React.createElement("${tagName}", ${propsObj}${childrenArgs})`;
                        const placeholder = generatePlaceholder(createElementCode);

                        // 替换当前匹配项
                        processed = processed.replace(fullMatch, placeholder);

                        // 重置正则索引，从头重新查找（因为字符串变了）
                        tagRegex.lastIndex = 0;
                    }

                    // 3. 还原剩余的占位符（通常是顶层组件）
                    // 循环直到没有占位符为止
                    const placeholderRegex = /%%JSX_PLACEHOLDER_(\d+)%%/;
                    while (placeholderRegex.test(processed)) {
                        processed = processed.replace(placeholderRegex, (_match, indexStr) => {
                            const index = parseInt(indexStr);
                            return placeholders[index];
                        });
                    }

                    return processed;
                };

                if (hasJSX) {
                     try {
                        processedCode = transpileJSX(viewCode);
                     } catch (e) {
                        console.error("JSX Transpile Error", e);
                     }
                }

                // 自动添加 return 如果用户只是定义了一个函数表达式

                // 自动添加 return 如果用户只是定义了一个函数表达式
                const trimmedCode = processedCode.trim();
                if (
                    !trimmedCode.startsWith('return') && 
                    (trimmedCode.startsWith('(') || trimmedCode.startsWith('function'))
                ) {
                    processedCode = `return ${processedCode}`;
                }

                // 创建一个函数来执行用户的自定义代码
                const createComponent = new Function(
                    'React',
                    'data',
                    'Badge',
                    'Button',
                    `
                    try {
                        ${processedCode}
                    } catch (error) {
                        console.error('画面代码执行错误:', error);
                        return null;
                    }
                    `
                )

                const component = createComponent(React, data, Badge, Button)

                if (component && typeof component === 'function') {
                    setViewComponent(() => component)
                    setError(null)
                } else {
                    setError('画面代码必须返回一个React组件')
                }
            } catch (err) {
                console.error('画面代码解析错误:', err)
                setError(err instanceof Error ? err.message : '代码执行失败')
            }
        } else if (viewId) {
            // 如果只提供了 viewId，显示占位内容
            setError(null)
            setViewComponent(() => {
                return function PlaceholderView({ data }: any) {
                    return (
                        <div className="p-4">
                            <p className="text-sm text-gray-600 mb-2">画面ID: {viewId}</p>
                            <p className="text-sm text-gray-500 mb-4">
                                提示：您可以在配置中添加 <code className="bg-gray-100 px-1 py-0.5 rounded">view.code</code> 字段来编写自定义画面代码。
                            </p>
                            <div className="mt-4 p-3 bg-gray-50 rounded">
                                <p className="text-xs text-gray-700 font-semibold mb-2">当前数据:</p>
                                <pre className="text-xs overflow-auto max-h-40">
                                    {JSON.stringify(data, null, 2)}
                                </pre>
                            </div>
                        </div>
                    )
                }
            })
        } else {
            setError('未提供画面ID或画面代码')
        }
    }, [viewCode, viewId, data, viewConfig])

    return (
        <div className="bg-white rounded-lg shadow-lg border border-gray-200 min-w-100 max-w-200 max-h-150 overflow-hidden">
            <div className="bg-gray-50 px-4 py-2 border-b border-gray-200 flex items-center justify-between">
                <h3 className="font-semibold text-sm text-gray-900">
                    {data?.name || data?.title || '画面视图'}
                </h3>
                {!hidenCloseBtn && (
                    <Button
                        variant="ghost"
                        size="sm"
                        onClick={onClose}
                        className="h-6 w-6 p-0 hover:bg-gray-200"
                    >
                        <X className="h-4 w-4" />
                    </Button>
                )}
            </div>
            <div className="overflow-y-auto max-h-[540px]">
                {error ? (
                    <div className="text-red-500 text-sm p-4 bg-red-50 rounded m-4">
                        <p className="font-semibold mb-2">画面加载错误:</p>
                        <p>{error}</p>
                    </div>
                ) : ViewComponent ? (
                    <ViewComponent data={data} />
                ) : (
                    <div className="text-gray-500 text-sm p-4">加载中...</div>
                )}
            </div>
        </div>
    )
}

export const getGeometryCenter = (geometry: any) => {
    const type = geometry.getType()

    switch (type) {
        case 'Point':
            return geometry.getCoordinates()

        case 'LineString':
            const lineCoords = geometry.getCoordinates()
            const midIndex = Math.floor(lineCoords.length / 2)
            return lineCoords[midIndex]

        case 'Polygon':
            const interiorPoint = geometry.getInteriorPoint().getCoordinates()
            return interiorPoint.slice(0, 2)

        case 'Circle':
            return geometry.getCenter()

        default:
            return null
    }
}

import Feature from 'ol/Feature'
import * as geom from 'ol/geom'
import * as style from 'ol/style'
import { fromLonLat } from 'ol/proj'
import isString from 'lodash/isString'
import merge from 'lodash/merge'

// 简化的 mapMaxResolution
const mapMaxResolution = 156543.03392804097;

export const getMapZoomforResolution = (resolution: number) => {
    return Math.log(mapMaxResolution / resolution) / Math.LN2;
}

export const getMarkerId = (record: any) => {
    return (record?.table || record?._table || record.tableId) + '|' + record?.id
}

// 简单的坐标转换，默认 EPSG:4326 -> EPSG:3857
export const getTransformTo3857 = (_coordinateType?: string) => {
    // 暂时忽略 coordinateType 的复杂判断，假设输入是 WGS84，输出 3857
    // 如果需要支持其他坐标系，这里需要 proj4
    return (coordinate: number[]) => fromLonLat(coordinate)
}

export const generateHalfCircle = (center: number[], radius: number, startAngle: number, endAngle: number) => {
    const angleStep = Math.PI / 180;
    const offset = 180
    let points = [];
    for (let angle = Math.PI * ((startAngle - offset) / (180)); angle <= Math.PI * ((endAngle - offset) / 180); angle += angleStep) {
        points.push([
            center[0] + Math.cos(angle) * radius,
            center[1] - Math.sin(angle) * radius  // Y 轴向下移动
        ])
    }
    return points
}

export const createFeature = ({ type, record, style: styleConfig, coordinate, coordinateType, markerTags, cellKey, tableGisConfig }: any) => {
    const transform = getTransformTo3857(coordinateType)
    let feature = new Feature({})

    if (!coordinate) return feature;

    if (type == 'Point') {
        feature = new Feature({
            geometry: new geom.Point(transform(coordinate)),
        });
    } else if (type == 'LineString') {
        feature = new Feature({
            geometry: new geom.LineString(coordinate.map((coord: number[]) => transform(coord)))
        })
    } else if (type == 'Polygon') {
        feature = new Feature({
            geometry: new geom.Polygon(coordinate.map((coord: number[][]) => coord.map(c => transform(c))))
        })
    } else if (type == 'Circle') {
        if (!coordinate?.center || !coordinate?.radius) return feature
        feature = new Feature({
            geometry: new geom.Circle(transform(coordinate.center), coordinate.radius),
        })
    } else if (type == 'Semicircle') {
        const { center, radius } = coordinate
        const { isClose, startAngle = 0, endAngle = 180 } = styleConfig || {}
        const transCenter = transform(center)
        const geo = generateHalfCircle(transCenter, radius, startAngle, endAngle)
        let geometry: geom.Geometry = new geom.LineString(geo)
        if (isClose) {
            geo.push(transCenter)
            geo.push(geo[0])
            geometry = new geom.Polygon([geo])
        }
        feature = new Feature({ geometry });
    }

    feature.setId(getMarkerId(record))
    feature.setProperties({
        markerRecord: record,
        markerType: type,
        markerInitStyle: styleConfig,
        markerTags: markerTags,
        markerLabel: record._label,
        cellKey,
        tableGisConfig
    }, true)
    return feature
}

export const createEmptyFeature = (record: any) => {
    let feature = new Feature({})
    feature.setId(getMarkerId(record))
    feature.setProperties({
        markerRecord: record,
        markerLabel: record._label,
    }, true)
    return feature
}

export function isInRange(current: number, min: number | null, max: number | null) {
    if (min === null && max === null) {
        return false;
    }
    const minValid = min === null || current >= min;
    const maxValid = max === null || current <= max;
    return minValid && maxValid;
}

export function clusterStyle(cluster: any, size: number) {
    return new style.Style({
        image: new style.Circle({
            radius: cluster?.radius || 18,
            fill: new style.Fill({
                color: cluster?.background || 'rgba(0, 0, 255, 0.6)'
            })
        }),
        text: new style.Text({
            font: `${cluster.font || 15}px sans-serif`,
            text: cluster?.text ? cluster?.text.indexOf('XX') > -1 ? cluster?.text?.replace('XX', size?.toString()) : cluster?.text : size?.toString(),
            fill: new style.Fill({
                color: cluster?.color || '#fff'
            })
        })
    })
}

export function parseIconScript({ iconScript, record, tags, style }: any) {
    if (!iconScript || typeof iconScript !== 'string') {
        return null;
    }
    try {
        // eslint-disable-next-line @typescript-eslint/no-implied-eval
        const scriptFn = new Function('record', 'tags', 'style', `
      try {
        const userFn = ${iconScript};
        return typeof userFn === 'function' ? userFn(record, tags, style) : null;
      } catch (e) {
        return null;
      }
    `);
        let result = scriptFn(record, tags, style)
        if (isString(result)) {
            // 假设 /rest 开头是相对路径，否则补上前缀（这里简化处理，直接返回）
            // result = result.startsWith('/rest') ? result : config('mediaUrl') + result
        }
        return result
    } catch (error) {
        console.error('图标脚本解析失败:', error);
        return null;
    }
}

export const createNumberLabelStyles = ({ geometry, baseStyle, textStyle = {} }: any) => {
    if (!geometry) {
        return baseStyle
    }

    const geoType = geometry.getType()
    let coordinates: number[][] = []

    if (geoType === 'LineString') {
        coordinates = (geometry as geom.LineString).getCoordinates() || []
    } else if (geoType === 'Polygon') {
        const rings = (geometry as geom.Polygon).getCoordinates() || []
        if (rings.length > 0) {
            coordinates = rings[0] || []
        }
    }

    if (!coordinates || coordinates.length === 0) {
        return baseStyle
    }

    // 如果是闭合多边形，去掉最后一个重复的点
    if (coordinates.length > 1) {
        const first = coordinates[0]
        const last = coordinates[coordinates.length - 1]
        if (first && last && first[0] === last[0] && first[1] === last[1]) {
            coordinates = coordinates.slice(0, coordinates.length - 1)
        }
    }

    // 默认文本样式
    const defaultTextStyle = {
        font: '12px Calibri,sans-serif',
        fillColor: '#000000',
        strokeColor: '#ffffff',
        strokeWidth: 2,
        offsetY: -12,
        ...textStyle
    }

    // 创建序号标签样式
    const labelStyles = coordinates.map((coord, index) => new style.Style({
        geometry: new geom.Point(coord),
        text: new style.Text({
            text: String(index + 1),
            font: defaultTextStyle.font,
            fill: new style.Fill({ color: defaultTextStyle.fillColor }),
            stroke: new style.Stroke({ color: defaultTextStyle.strokeColor, width: defaultTextStyle.strokeWidth }),
            offsetY: defaultTextStyle.offsetY,
        })
    }))

    return [baseStyle, ...labelStyles]
};


// 样式创建相关
// 默认标记图标（绿色图钉）- 与主文件保持一致
const defaultIcon = 'data:image/svg+xml;base64,'

export const createIconClass = ({ iconSrc, color, offsetX, offsetY, scale, rotation, displacementX, displacementY, rotateWithView, anchor }: any, zoomScale: any) => {

    const baseScale = scale ? scale : 1
    let normalizedSrc = iconSrc
    if (typeof normalizedSrc === 'string' && normalizedSrc) {
        try {
            normalizedSrc = encodeURI(normalizedSrc)
        } catch (e) {
            normalizedSrc = iconSrc
        }
    }

    const iconOptions: any = {
        src: normalizedSrc || defaultIcon,
        offset: [offsetX || 0, offsetY || 0],
        scale: zoomScale ? zoomScale * baseScale : baseScale,
        anchor: anchor || [0.5, 0.5],
        anchorXUnits: 'fraction',
        anchorYUnits: 'fraction',
        rotation: rotation || 0,
        rotateWithView: rotateWithView !== undefined ? rotateWithView : true,
        displacement: [displacementX || 0, displacementY || 0]
    }

    if (color) {
        iconOptions.color = color
    }

    return new style.Icon(iconOptions)
}

export const createTextClass = ({ text, font, fill, stroke, scale, rotation, offsetX, offsetY, backgroundFill }: any, zoomScale?: any) => {

    const baseScale = scale ? scale : 1

    return new style.Text({
        text: text || '',
        font: font || `12px Calibri,sans-serif`,
        fill: new style.Fill({ color: fill || 'rgba(0,0,0,1)' }),
        stroke: new style.Stroke({ color: stroke || 'rgba(255,255,255,1)', width: 2 }),
        scale: zoomScale ? zoomScale * baseScale : baseScale,
        rotation: rotation || 0,
        offsetX: offsetX || 0,
        offsetY: offsetY || 0,
        backgroundFill
    })
}

export const createStyleClass = ({
    markerType,
    style: markerStyle,
    zIndex,
    zoomScale
}: any) => {

    const {
        icon, line, polygon, circle, semicircle, text,
        textSetting, iconUrl, iconSetting, backgroundFill
    } = markerStyle || {}

    let iconStyle = icon || {}
    let textStyle = text || {}

    if (textSetting) { textStyle = merge(textSetting, textStyle) }
    if (backgroundFill && !textStyle.fill) { textStyle['fill'] = backgroundFill }

    if (markerType == 'Point') {
        if (iconUrl && !iconStyle?.iconSrc) {
            iconStyle.iconSrc = iconUrl || {}
        }
        if (iconSetting) {
            iconStyle = merge(iconSetting, iconStyle || {})
        }
        return new style.Style({
            image: createIconClass(iconStyle || {}, zoomScale),
            text: createTextClass(textStyle || {}, zoomScale),
            zIndex: zIndex || 0,
        })
    } else {
        // 简化处理线面圆的样式获取
        // styleConfig (markerStyle) 包含了 { icon, line, polygon, ... } 以及基础属性 { color, width, ... }

        let typeStyle: any = {}
        if (markerType === 'LineString') typeStyle = line
        else if (markerType === 'Polygon') typeStyle = polygon
        else if (markerType === 'Circle') typeStyle = circle
        else if (markerType === 'Semicircle') typeStyle = semicircle

        // typeStyle 是特定类型的样式（如 line: { color: 'blue', width: 8 }）

        const { fill, fillColor: typeFill, color, width, lineDash } = typeStyle || {}

        // 优先级：
        // 1. typeStyle 中的属性 (line.color, line.width 等)
        // 2. typeStyle 中的 fill/fillColor
        // 3. markerStyle 中的全局属性 (markerStyle.color, markerStyle.width 等)

        let finalFillColor = fill || typeFill
        if (!finalFillColor) finalFillColor = markerStyle?.fillColor

        let finalStrokeColor = color
        if (!finalStrokeColor) finalStrokeColor = markerStyle?.color

        let finalStrokeWidth = width
        if (finalStrokeWidth === undefined) finalStrokeWidth = markerStyle?.width
        if (finalStrokeWidth === undefined) finalStrokeWidth = 2

        let finalStrokeLineDash = lineDash

        return new style.Style({
            text: createTextClass(textStyle || {}),
            zIndex: zIndex || 0,
            fill: finalFillColor && new style.Fill({ color: finalFillColor }),
            stroke: new style.Stroke({
                color: finalStrokeColor,
                width: finalStrokeWidth,
                lineDash: (finalStrokeLineDash == "dashed" || finalStrokeLineDash == 'dash') ? [10, 10] : undefined
            }),
        })
    }
}

export function getGeometryCenter(geometry: geom.Geometry) {
    const type = geometry.getType();

    switch (type) {
        case 'Point':
            return (geometry as geom.Point).getCoordinates();

        case 'LineString':
            const lineCoords = (geometry as geom.LineString).getCoordinates();
            const midIndex = Math.floor(lineCoords.length / 2);
            return lineCoords[midIndex];

        case 'Polygon':
            const interiorPoint = (geometry as geom.Polygon).getInteriorPoint().getCoordinates()
            return interiorPoint.slice(0, 2)

        case 'Circle':
            return (geometry as geom.Circle).getCenter();

        default:
            return null;
    }
}

import * as React from "react"
import { cn } from "@/lib/utils"
import Map from 'ol/Map'
import View from 'ol/View'
import TileLayer from 'ol/layer/Tile'
import XYZ from 'ol/source/XYZ'
import { fromLonLat, transformExtent } from 'ol/proj'
import { Zoom, ScaleLine, defaults as defaultControls } from 'ol/control'
import 'ol/ol.css'

// Map Context 用于向子组件传递 map 实例
export interface MapContextValue {
  map: Map | null
}

export const MapContext = React.createContext<MapContextValue>({ map: null })

// Hook 用于获取 map 实例
export const useMap = () => {
  const context = React.useContext(MapContext)
  return context.map
}

export interface ViewOptions {
  position?: {
    center?: [number, number]
    pick?: boolean
  }
  resetCenter?: {
    tableData?: Array<{ id: string; _table: string }>
  }
  zoom?: number
  maxZoom?: number
  minZoom?: number
  rotation?: number
  recordRotationActive?: boolean
  resolution?: number
  animation?: boolean
  duration?: number
}

export interface ZoomOption {
  show?: boolean
  zoomInTipLabel?: string
  zoomOutTipLabel?: string
  minZoom?: number
  maxZoom?: number
}

export interface ScaleLineOption {
  show?: boolean
  minWidth?: number
  units?: 'metric' | 'us' | 'nautical' | 'imperial' | 'degrees'
  steps?: number
  bar?: boolean
  text?: boolean
}

export interface ExtentOption {
  westLon?: number
  southLat?: number
  eastLon?: number
  northLat?: number
}

export interface MapContainerProps {
  /**
   * 视图配置
   */
  viewOptions?: ViewOptions
  /**
   * 缩放控件配置
   */
  zoomOption?: ZoomOption
  /**
   * 比例尺配置
   */
  scaleLine?: ScaleLineOption
  /**
   * 拖拽边界范围
   */
  extentOption?: ExtentOption
  /**
   * 宽度
   */
  width?: number | string
  /**
   * 高度
   */
  height?: number | string
  /**
   * CSS 类名
   */
  className?: string
  /**
   * 单元格唯一标识
   */
  cellKey?: string
  /**
   * 子元素
   */
  children?: React.ReactNode
}

// 默认中心点坐标 (北京)
const DEFAULT_CENTER: [number, number] = [116.391, 39.9042]

// 高德地图瓦片图层
const createTileLayer = () => {
  return new TileLayer({
    source: new XYZ({
      url: 'http://wprd0{1-4}.is.autonavi.com/appmaptile?lang=zh_cn&size=1&style=7&x={x}&y={y}&z={z}',
      crossOrigin: 'anonymous',
    }),
  })
}

const MapContainer = React.forwardRef<HTMLDivElement, MapContainerProps>(
  (
    {
      className,
      viewOptions = {
        position: {
          center: DEFAULT_CENTER,
          pick: false
        },
        zoom: 10,
        maxZoom: 18,
        minZoom: 3,
        rotation: 0,
        recordRotationActive: false,
        animation: true,
        duration: 1000
      },
      zoomOption = {
        show: true,
        zoomInTipLabel: '放大',
        zoomOutTipLabel: '缩小',
        minZoom: 3,
        maxZoom: 18
      },
      scaleLine = {
        show: true,
        bar: false,
        text: false
      },
      extentOption,
      width = '100%',
      height = '100%',
      cellKey,
      children,
      ...props
    },
    ref
  ) => {
    const containerRef = React.useRef<HTMLDivElement>(null)
    const mapRef = React.useRef<HTMLDivElement>(null)
    const [mapInstance, setMapInstance] = React.useState<Map | null>(null)
    const [mapReady, setMapReady] = React.useState(false)

    // 合并 ref
    React.useImperativeHandle(ref, () => containerRef.current as HTMLDivElement)

    // 获取配置值
    const center = viewOptions?.position?.center || DEFAULT_CENTER
    const zoom = viewOptions?.zoom ?? 10
    const maxZoom = viewOptions?.maxZoom ?? 18
    const minZoom = viewOptions?.minZoom ?? 3
    const rotation = viewOptions?.rotation ?? 0
    const animation = viewOptions?.animation ?? true
    const duration = viewOptions?.duration ?? 1000

    // 初始化地图
    React.useEffect(() => {
      if (!mapRef.current || mapInstance) return

      // 构建视图配置
      const viewConfig: Record<string, unknown> = {
        center: fromLonLat(center),
        zoom,
        maxZoom,
        minZoom,
        rotation: (rotation * Math.PI) / 180, // 角度转弧度
      }

      // 处理边界范围
      if (extentOption) {
        const { northLat, eastLon, southLat, westLon } = extentOption
        if (northLat && eastLon && southLat && westLon) {
          const fixedExtent = [
            Math.min(westLon, eastLon),
            southLat,
            Math.max(westLon, eastLon),
            northLat
          ]
          viewConfig.extent = transformExtent(fixedExtent, 'EPSG:4326', 'EPSG:3857')
        }
      }

      // 创建地图实例
      const map = new Map({
        target: mapRef.current,
        layers: [createTileLayer()],
        view: new View(viewConfig),
        controls: defaultControls({
          zoom: false,
          attribution: false,
          rotate: false,
        }),
      })

      // 添加缩放控件
      if (zoomOption?.show) {
        map.addControl(new Zoom({
          zoomInTipLabel: zoomOption.zoomInTipLabel || '放大',
          zoomOutTipLabel: zoomOption.zoomOutTipLabel || '缩小',
        }))
      }

      // 添加比例尺
      if (scaleLine?.show) {
        map.addControl(new ScaleLine({
          units: scaleLine.units || 'metric',
          bar: scaleLine.bar || false,
          text: scaleLine.text || false,
          minWidth: scaleLine.minWidth,
          steps: scaleLine.steps,
        }))
      }

      setMapInstance(map)
      setMapReady(true)

      // 监听容器大小变化
      const resizeObserver = new ResizeObserver(() => {
        map.updateSize()
      })
      if (mapRef.current) {
        resizeObserver.observe(mapRef.current)
      }

      return () => {
        resizeObserver.disconnect()
        if (map) {
          map.setTarget(undefined)
          setMapInstance(null)
        }
      }
    }, [])

    // 更新中心位置
    React.useEffect(() => {
      if (!mapInstance || !mapReady) return
      const view = mapInstance.getView()
      const newCenter = fromLonLat(center)

      if (animation) {
        view.animate({ center: newCenter, duration })
      } else {
        view.setCenter(newCenter)
      }
    }, [center[0], center[1], mapReady])

    // 更新缩放级别
    React.useEffect(() => {
      if (!mapInstance || !mapReady) return
      const view = mapInstance.getView()

      if (animation) {
        view.animate({ zoom, duration })
      } else {
        view.setZoom(zoom)
      }
    }, [zoom, mapReady])

    // 更新最大/最小缩放
    React.useEffect(() => {
      if (!mapInstance || !mapReady) return
      const view = mapInstance.getView()
      view.setMaxZoom(maxZoom)
      view.setMinZoom(minZoom)
    }, [maxZoom, minZoom, mapReady])

    // 更新旋转角度
    React.useEffect(() => {
      if (!mapInstance || !mapReady) return
      const view = mapInstance.getView()
      const radians = (rotation * Math.PI) / 180

      if (animation) {
        view.animate({ rotation: radians, duration })
      } else {
        view.setRotation(radians)
      }
    }, [rotation, mapReady])

    // 更新缩放控件
    React.useEffect(() => {
      if (!mapInstance || !mapReady) return
      const controls = mapInstance.getControls().getArray()
      const zoomControl = controls.find((c: unknown) => c instanceof Zoom)

      if (!zoomOption?.show && zoomControl) {
        mapInstance.removeControl(zoomControl)
      } else if (zoomOption?.show && !zoomControl) {
        mapInstance.addControl(new Zoom({
          zoomInTipLabel: zoomOption.zoomInTipLabel || '放大',
          zoomOutTipLabel: zoomOption.zoomOutTipLabel || '缩小',
        }))
      }
    }, [zoomOption?.show, mapReady, mapInstance])

    // 更新比例尺
    React.useEffect(() => {
      if (!mapInstance || !mapReady) return
      const controls = mapInstance.getControls().getArray()
      const scaleLineControl = controls.find((c: unknown) => c instanceof ScaleLine)

      if (scaleLineControl) {
        mapInstance.removeControl(scaleLineControl)
      }

      if (scaleLine?.show) {
        mapInstance.addControl(new ScaleLine({
          units: scaleLine.units || 'metric',
          bar: scaleLine.bar || false,
          text: scaleLine.text || false,
          minWidth: scaleLine.minWidth,
          steps: scaleLine.steps,
        }))
      }
    }, [scaleLine?.show, scaleLine?.units, scaleLine?.bar, scaleLine?.text, mapReady, mapInstance])

    return (
      <div
        ref={containerRef}
        className={cn(
          "relative overflow-hidden",
          className
        )}
        style={{
          width: typeof width === 'number' ? `${width}px` : width,
          height: typeof height === 'number' ? `${height}px` : height
        }}
        data-cell-key={cellKey}
        {...props}
      >
        {/* OpenLayers 地图容器 */}
        <div 
          ref={mapRef} 
          className="absolute inset-0"
          style={{ width: '100%', height: '100%' }}
        />

        {/* 子元素容器 - 通过 Context 传递 map 实例 */}
        {children && (
          <MapContext.Provider value={{ map: mapInstance }}>
            <div className="absolute inset-0 pointer-events-none z-10">
              <div className="pointer-events-auto">
                {mapReady ? children : null}
              </div>
            </div>
          </MapContext.Provider>
        )}
      </div>
    )
  }
)

MapContainer.displayName = "MapContainer"

export { MapContainer }
